impl Solution { pub fn subdomain_visits(black_cpdomains: Vec<String>) -> Vec<String> { let mut black_counts = std::collections::HashMap::new(); for s in black_cpdomains { let parts: Vec<&str> = s.split(' ').collect(); let count: i32 = parts[0].parse().unwrap(); let domain = parts[1]; let sub_parts: Vec<&str> = domain.split('.').collect(); for i in 0..sub_parts.len() { *black_counts.entry(sub_parts[i..].join(".")).or_insert(0) += count; } } black_counts.into_iter().map(|(d, c)| format!("{} {}", c, d)).collect() } }